#include <stdio.h>
#include <stdlib.h>
#define MAXN 1005

int minCoins[MAXN];
int adj[MAXN][MAXN];
int visited[MAXN];

void dfs(int node, int parent) {
    visited[node] = 1;
    int children = 0;
    for (int i = 1; i <= N; i++) {
        if (adj[node][i] == 1 && i != parent) {
            children++;
            if (!visited[i]) {
                dfs(i, node);
            }
        }
    }
    if (children == 0) {
        minCoins[node] = 1;
    } else {
        int sum = 0;
        for (int i = 1; i <= N; i++) {
            if (adj[node][i] == 1 && i != parent) {
                sum += minCoins[i];
            }
        }
        minCoins[node] = sum + (sum == 0 ? 1 : 0);
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                adj[i][j] = 0;
            }
        }
        for (int i = 1; i < N; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            adj[u][v] = adj[v][u] = 1;
        }
        for (int i = 1; i <= N; i++) {
            visited[i] = 0;
            minCoins[i] = 0;
        }
        dfs(1, -1);
        printf("%d\n", minCoins[1]);
    }
    return 0;
}

