import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    static int[] minCoins;
    static ArrayList<Integer>[] adj;
    static boolean[] visited;
    static int N;

    public static void dfs(int node, int parent) {
        visited[node] = true;
        int children = 0;
        for (int i = 0; i < adj[node].size(); i++) {
            if (adj[node].get(i) != parent) {
                children++;
                if (!visited[adj[node].get(i)]) {
                    dfs(adj[node].get(i), node);
                }
            }
        }
        if (children == 0) {
            minCoins[node] = 1;
        } else {
            int sum = 0;
            for (int i = 0; i < adj[node].size(); i++) {
                if (adj[node].get(i) != parent) {
                    sum += minCoins[adj[node].get(i)];
                }
            }
            minCoins[node] = sum + (sum == 0 ? 1 : 0);
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            N = sc.nextInt();
            minCoins = new int[N + 1];
            adj = new ArrayList[N + 1];
            visited = new boolean[N + 1];
            for (int i = 0; i <= N; i++) {
                adj[i] = new ArrayList<>();
                visited[i] = false;
                minCoins[i] = 0;
            }
            for (int i = 1; i < N; i++) {
                int u = sc.nextInt();
